import { NavLink } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import {
  LayoutGrid, ClipboardList,
  Receipt, Package, Settings, Users, LogOut, Sun, Moon, TrendingUp, Play
} from 'lucide-react';

const navItems = [
  { to: '/session', icon: Play, label: 'Session' },
  { to: '/tables', icon: LayoutGrid, label: 'Tables' },
  { to: '/orders', icon: ClipboardList, label: 'Orders' },
  { to: '/billing', icon: Receipt, label: 'Bills' },
  { to: '/inventory', icon: Package, label: 'Stock', adminOnly: true },
  { to: '/users', icon: Users, label: 'Users', adminOnly: true },
  { to: '/reports', icon: TrendingUp, label: 'Reports', adminOnly: true },
  { to: '/settings', icon: Settings, label: 'Setup', adminOnly: true },
];

export default function Sidebar() {
  const { currentUser, logout, theme, toggleTheme, currentSession } = useApp();
  const isAdmin = currentUser?.role === 'admin';

  const visibleItems = navItems.filter(item => !item.adminOnly || isAdmin);

  return (
    <aside className="sidebar">
      <div className="sidebar-brand-icon" title="RestoGrow POS">RG</div>

      <nav className="sidebar-nav">
        {visibleItems.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            end={item.to === '/session'}
            className={({ isActive }) => `sidebar-link${isActive ? ' active' : ''}`}
            title={item.label}
          >
            <item.icon size={18} />
            <span className="sidebar-label">{item.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* Session indicator */}
      {currentSession && (
        <div style={{
          width: '8px', height: '8px', borderRadius: '50%',
          background: 'var(--brand-success)',
          boxShadow: '0 0 6px var(--brand-success)',
          margin: '4px 0',
          animation: 'pulse 2s infinite',
        }} title="Session Active" />
      )}

      <div className="sidebar-footer">
        <button className="theme-toggle" onClick={logout} title="Logout">
          <LogOut size={14} />
        </button>
      </div>

    </aside>
  );
}

import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { syncAll, authenticateUser, setTenant, getTenant, subscribeToChanges } from '../store/data';

const ToastContext = createContext();

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);
  const addToast = useCallback((message, type = 'info', duration = 3000) => {
    const id = Date.now();
    setToasts([{ id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, duration);
  }, []);
  return (
    <ToastContext.Provider value={{ addToast }}>
      {children}
      <div className="toast-container">
        {toasts.map(t => (
          <div key={t.id} className={`toast toast-${t.type}`}>{t.message}</div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export const useToast = () => useContext(ToastContext);

// ===== APP CONTEXT =====
const AppContext = createContext();

export function AppProvider({ children }) {
  const [theme, setTheme] = useState('light');
  const [tenantId, setTenantId] = useState(() => localStorage.getItem('rg_tenant_id'));
  const [currentUser, setCurrentUser] = useState(() => {
    try {
      const u = localStorage.getItem('rg_current_user');
      return u ? JSON.parse(u) : null;
    } catch { return null; }
  });

  const [data, setData] = useState({
    tables: [], sections: [], categories: [], menu_items: [], users: [], orders: [], order_items: [], bills: [], bill_items: [], sessions: [],
    config: { restaurantName: 'RestoGrow', currency: 'Γé╣', taxRate: 0, serviceChargeRate: 0 },
    restaurant: { status: 'active', name: '' }
  });

  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  // Check URL for RID (Restaurant ID)
  useEffect(() => {
    const params = new URLSearchParams(window.location.hash.split('?')[1]);
    const rid = params.get('rid');
    if (rid) {
      localStorage.setItem('rg_tenant_id', rid);
      setTenantId(rid);
      setTenant(rid);
    } else if (tenantId) {
      setTenant(tenantId);
    }
  }, [tenantId]);

  const loadData = useCallback(async () => {
    if (!getTenant()) {
      setLoading(false);
      return;
    }
    setRefreshing(true);
    try {
      const result = await syncAll();
      if (result) {
        setData(prev => {
          // Merge logic: only overwrite if result has data for that table
          const newData = { ...prev };
          Object.keys(result).forEach(k => {
            if (result[k] !== undefined) newData[k] = result[k];
          });
          return newData;
        });
      }
    } catch (err) {
      console.error('Sync error:', err);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    let sub = null;
    if (getTenant()) {
      sub = subscribeToChanges(() => loadData());
    }
    return () => { if (sub) sub.unsubscribe(); };
  }, [loadData, tenantId]);

  const login = useCallback(async (user) => {
    setCurrentUser(user);
    localStorage.setItem('rg_current_user', JSON.stringify(user));
    if (user.restaurant_id) {
      setTenantId(user.restaurant_id);
      localStorage.setItem('rg_tenant_id', user.restaurant_id);
      setTenant(user.restaurant_id);
    }
  }, []);

  const logout = useCallback(() => {
    setCurrentUser(null);
    localStorage.removeItem('rg_current_user');
    setTenantId(null);
    localStorage.removeItem('rg_tenant_id');
    setTenant(null);
    window.location.hash = '/'; // Redirect to login
  }, []);

  const refresh = useCallback(async () => { await loadData(); }, [loadData]);

  const currentSession = (data.sessions || []).find(s => s.status === 'active') || null;

  return (
    <AppContext.Provider value={{
      theme, currentUser, login, logout, tenantId,
      config: data.config,
      tables: data.tables,
      sections: data.sections,
      menuItems: data.menu_items || [],
      categories: data.categories,
      orders: data.orders,
      bills: data.bills,
      users: data.users,
      sessions: data.sessions,
      inventory_log: data.inventory_log || [],
      restaurant: data.restaurant,
      currentSession,
      refresh,
      loading,
      refreshing
    }}>
      {children}
    </AppContext.Provider>
  );
}

export const useApp = () => useContext(AppContext);

import { useState } from 'react';
import { useApp } from '../context/AppContext';
import { printBillDirect } from '../utils/print';
import { Search, Printer, Receipt } from 'lucide-react';

export default function BillingHistoryPage() {
  const { bills: rawBills, config, refresh, refreshing = false } = useApp();
  const bills = [...(rawBills || [])].reverse();
  const [searchQuery, setSearchQuery] = useState('');
  const [paymentFilter, setPaymentFilter] = useState('all');

  const filteredBills = (bills || []).filter(b => {
    const matchSearch = !searchQuery || b.billNumber?.toLowerCase().includes(searchQuery.toLowerCase()) || String(b.tableNumber || '').includes(searchQuery);
    const matchPayment = paymentFilter === 'all' || b.paymentMode === paymentFilter;
    return matchSearch && matchPayment;
  });

  const handlePrint = (bill) => {
    printBillDirect(bill);
  };

  const todayTotal = bills.filter(b => {
    const d = b.createdAt || b.created_at;
    return d?.startsWith(new Date().toISOString().split('T')[0]);
  }).reduce((s, b) => s + (b.total || 0), 0);

  return (
    <div className="page-content">
      <div className="page-header">
        <div className="page-title">
          <Receipt size={16} /> BILLS
          <span style={{ fontSize: '10px', color: 'var(--text-tertiary)', fontWeight: 500 }}>
            {bills.length} total ┬╖ Today: {config.currency}{todayTotal}
          </span>
        </div>
      </div>

      <div style={{ display: 'flex', gap: '8px', marginBottom: '10px' }}>
        <div className="search-input-wrapper" style={{ flex: 1, minWidth: '180px' }}>
          <Search />
          <input className="input" placeholder="Search bill # or table..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
        </div>
        <select className="select" value={paymentFilter} onChange={e => setPaymentFilter(e.target.value)} style={{ width: '120px' }}>
          <option value="all">All</option>
          <option value="Cash">Cash</option>
          <option value="Card">Card</option>
          <option value="UPI">UPI</option>
        </select>
      </div>

      <div className="card">
        <div className="card-body" style={{ padding: 0, maxHeight: 'calc(100vh - 180px)', overflow: 'auto' }}>
          <table className="data-table">
            <thead><tr><th>BILL #</th><th>TIME</th><th>TABLE</th><th>ITEMS</th><th>TOTAL</th><th>PAY</th><th></th></tr></thead>
            <tbody>
              {filteredBills.map(bill => (
                <tr key={bill.id}>
                  <td style={{ fontFamily: 'var(--font-mono)', fontWeight: 700 }}>{bill.billNumber}</td>
                  <td style={{ fontSize: '10px', color: 'var(--text-tertiary)' }}>{new Date(bill.createdAt || bill.created_at).toLocaleString()}</td>
                  <td style={{ fontFamily: 'var(--font-mono)' }}>T{bill.tableNumber}</td>
                  <td>{(bill.items || []).length}</td>
                  <td style={{ fontWeight: 800, fontFamily: 'var(--font-mono)', color: 'var(--brand-success)' }}>{config.currency}{bill.total}</td>
                  <td><span className="badge badge-info">{bill.paymentMode}</span></td>
                  <td><button className="btn btn-ghost btn-sm" onClick={() => handlePrint(bill)}><Printer size={12} /></button></td>
                </tr>
              ))}
              {filteredBills.length === 0 && (
                <tr><td colSpan="7" style={{ textAlign: 'center', padding: '32px', color: 'var(--text-tertiary)' }}>No bills</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp, useToast } from '../context/AppContext';
import { generateBill } from '../store/data';
import { printBillDirect } from '../utils/print';
import { CreditCard, Banknote, Smartphone, ArrowLeft, Printer } from 'lucide-react';

export default function BillingPage() {
  const { orderId } = useParams();
  const navigate = useNavigate();
  const { config = {}, refresh, orders = [], refreshing = false } = useApp();
  const { addToast } = useToast();

  const order = (orders || []).find(o => o.id === orderId);
  const [paymentMode, setPaymentMode] = useState('Cash');
  const [discount, setDiscount] = useState(0);
  const [generatedBill, setGeneratedBill] = useState(null);

  if (!order) {
    return (
      <div className="page-content"><div className="empty-state">
        <p className="empty-state-title">Order not found</p>
        <button className="btn btn-primary" onClick={() => navigate('/tables')}>Back</button>
      </div></div>
    );
  }

  const subtotal = (order?.items || []).reduce((s, i) => s + ((i.price || 0) * (i.quantity || 0)), 0);
  const taxAmount = (subtotal * config.taxRate) / 100;
  const serviceCharge = (subtotal * config.serviceChargeRate) / 100;
  const discountAmount = (subtotal * discount) / 100;
  const total = subtotal + taxAmount + serviceCharge - discountAmount;

  const handleGenerateBill = async () => {
    try {
      const result = await generateBill(orderId, paymentMode, discount);
      if (result.bill) { setGeneratedBill(result.bill); refresh(); addToast('BILL GENERATED', 'success'); }
      else addToast('Failed', 'error');
    } catch (e) { addToast('Failed: ' + e.message, 'error'); }
  };

  const handlePrintBill = () => {
    if (!generatedBill) return;
    printBillDirect(generatedBill);
  };

  if (generatedBill) {
    return (
      <div className="page-content">
        <div style={{ maxWidth: '400px', margin: '0 auto', textAlign: 'center' }}>
          <div style={{ fontSize: '32px', marginBottom: '8px' }}>Γ£ô</div>
          <div style={{ fontFamily: 'var(--font-mono)', fontWeight: 800, marginBottom: '4px' }}>BILL GENERATED</div>
          <div style={{ fontSize: '11px', color: 'var(--text-tertiary)', fontFamily: 'var(--font-mono)', marginBottom: '16px' }}>{generatedBill.billNumber}</div>

          <div className="bill-preview" style={{ marginBottom: '16px', textAlign: 'left' }}>
            <div className="bill-header">
              <div className="bill-restaurant-name">{generatedBill.restaurantName || 'POS'}</div>
              {generatedBill.gstNumber && <div style={{ fontSize: '9px', color: '#666' }}>GST: {generatedBill.gstNumber}</div>}
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '10px', marginBottom: '4px' }}>
              <span>{generatedBill.billNumber}</span><span>{generatedBill.tableNumber}</span>
            </div>
            <hr className="bill-divider" />
            {(generatedBill.items || []).map((item, i) => (
              <div key={i} className="bill-item-row"><span>{item.name} ├ù{item.quantity}</span><span>Γé╣{item.price * item.quantity}</span></div>
            ))}
            <hr className="bill-divider" />
            <div className="bill-total-row" style={{ fontWeight: 400 }}><span>Subtotal</span><span>Γé╣{generatedBill.subtotal}</span></div>
            {generatedBill.taxAmount > 0 && <div className="bill-total-row" style={{ fontWeight: 400, fontSize: '10px' }}><span>Tax {generatedBill.taxRate}%</span><span>Γé╣{Math.round(generatedBill.taxAmount)}</span></div>}
            {generatedBill.discountAmount > 0 && <div className="bill-total-row" style={{ fontWeight: 400, fontSize: '10px', color: '#00B894' }}><span>Discount {generatedBill.discount}%</span><span>-Γé╣{Math.round(generatedBill.discountAmount)}</span></div>}
            <hr className="bill-divider" />
            <div className="bill-total-row"><span>TOTAL</span><span>Γé╣{generatedBill.total}</span></div>
            <div style={{ fontSize: '10px', marginTop: '4px' }}>Payment: {generatedBill.paymentMode}</div>
          </div>

          <div style={{ display: 'flex', gap: '8px' }}>
            <button className="btn btn-secondary btn-lg" style={{ flex: 1 }} onClick={() => navigate('/tables')}>
              TABLES
            </button>
            <button className="btn btn-primary btn-lg" style={{ flex: 1 }} onClick={handlePrintBill}>
              <Printer size={14} /> PRINT
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="page-content">
      <div style={{ maxWidth: '500px', margin: '0 auto' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '16px' }}>
          <button className="btn btn-ghost btn-icon" onClick={() => navigate(`/order/${order.tableId}`)}>
            <ArrowLeft size={16} />
          </button>
          <div className="page-title" style={{ borderBottom: 'none', paddingBottom: 0 }}>
            BILLING ΓÇö {order.tableNumber}
          </div>
        </div>

        {/* Items */}
        <div className="card" style={{ marginBottom: '12px' }}>
          <div className="card-body" style={{ padding: 0 }}>
            <table className="data-table">
              <thead><tr><th>ITEM</th><th>QTY</th><th>AMT</th></tr></thead>
              <tbody>
                {(order?.items || []).map(item => (
                  <tr key={item.id}>
                    <td style={{ fontWeight: 600 }}>{item.name}</td>
                    <td style={{ fontFamily: 'var(--font-mono)' }}>{item.quantity}</td>
                    <td style={{ fontWeight: 700, fontFamily: 'var(--font-mono)' }}>{config.currency}{item.price * item.quantity}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Payment */}
        <div className="card" style={{ marginBottom: '12px' }}>
          <div className="card-body">
            <div style={{ fontSize: '11px', fontWeight: 700, fontFamily: 'var(--font-mono)', marginBottom: '8px', color: 'var(--text-secondary)' }}>PAYMENT METHOD</div>
            <div className="payment-modes">
              {[
                { mode: 'Cash', icon: Banknote },
                { mode: 'Card', icon: CreditCard },
                { mode: 'UPI', icon: Smartphone },
              ].map(p => (
                <button key={p.mode}
                  className={`payment-mode-btn ${paymentMode === p.mode ? 'active' : ''}`}
                  onClick={() => setPaymentMode(p.mode)}>
                  <p.icon size={18} />
                  <span>{p.mode}</span>
                </button>
              ))}
            </div>

            <div className="input-group">
              <label className="input-label">Discount (%)</label>
              <input type="number" className="input" value={discount}
                onChange={e => setDiscount(Math.max(0, Math.min(100, Number(e.target.value))))}
                min="0" max="100" />
            </div>
          </div>
        </div>

        {/* Total */}
        <div className="card" style={{ marginBottom: '12px' }}>
          <div className="card-body">
            <div className="order-summary-row"><span>Subtotal</span><span>{config.currency}{subtotal}</span></div>
            {config.taxRate > 0 && <div className="order-summary-row"><span>Tax {config.taxRate}%</span><span>{config.currency}{Math.round(taxAmount)}</span></div>}
            {config.serviceChargeRate > 0 && <div className="order-summary-row"><span>Service {config.serviceChargeRate}%</span><span>{config.currency}{Math.round(serviceCharge)}</span></div>}
            {discount > 0 && <div className="order-summary-row" style={{ color: 'var(--brand-success)' }}><span>Discount {discount}%</span><span>-{config.currency}{Math.round(discountAmount)}</span></div>}
            <div className="order-summary-row total"><span>TOTAL</span><span>{config.currency}{Math.round(total)}</span></div>
          </div>
        </div>

        <button className="btn btn-success btn-lg" style={{ width: '100%', fontSize: '14px' }} onClick={handleGenerateBill}>
          COMPLETE ΓÇö {config.currency}{Math.round(total)}
        </button>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useApp, useToast } from '../context/AppContext';
import { addStock, addMenuItem, addCategory, updateCategory, deleteCategory, getInventoryLog, getLowStockItems } from '../store/data';
import { Package, AlertTriangle, Plus, Search, PlusCircle, Wine, Coffee, Edit3, Trash2 } from 'lucide-react';

export default function InventoryPage() {
  const { menuItems = [], inventory_log = [], categories = [], config = {}, refresh, currentUser, refreshing = false } = useApp();
  const { addToast } = useToast();
  const isAdmin = currentUser?.role === 'admin';

  const [activeTab, setActiveTab] = useState('stock');
  const [searchQuery, setSearchQuery] = useState('');
  const [stockModal, setStockModal] = useState(null);
  const [addQty, setAddQty] = useState('');
  const [addItemModal, setAddItemModal] = useState(null); // 'bar' or 'kitchen'
  const [newItemForm, setNewItemForm] = useState({
    name: '', code: '', price: '', categoryId: '', stock: '', unit: 'bottle', isVeg: true,
  });
  // Category management
  const [catModal, setCatModal] = useState(null);
  const [catForm, setCatForm] = useState({ name: '', color: '#6C5CE7', icon: '≡ƒì╜∩╕Å', shortcut: '', type: 'bar' });

  const lowStockItems = getLowStockItems(menuItems);
  const inventoryLog = getInventoryLog(inventory_log).reverse().slice(0, 50);

  const isKitchenEnabled = config.isKitchenEnabled !== false;
  const isBarEnabled = config.isBarEnabled !== false;
  const barLabel = config.barLabel || 'Bar';
  const kitchenLabel = config.kitchenLabel || 'Kitchen';

  // Classify categories
  const barCats = categories.filter(c => c.type === 'bar');
  const kitchenCats = categories.filter(c => c.type === 'kitchen');
  const barCatIds = barCats.map(c => c.id);
  const kitchenCatIds = kitchenCats.map(c => c.id);

  // Filter by search across all items
  const searchFiltered = menuItems.filter(i =>
    !searchQuery || i.name?.toLowerCase().includes(searchQuery.toLowerCase()) || i.code?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const barItems = isBarEnabled ? searchFiltered.filter(i => barCatIds.includes(i.categoryId)) : [];
  const kitchenItems = isKitchenEnabled ? searchFiltered.filter(i => kitchenCatIds.includes(i.categoryId)) : [];
  const uncategorized = isBarEnabled ? searchFiltered.filter(i => !barCatIds.includes(i.categoryId) && !kitchenCatIds.includes(i.categoryId)) : [];

  const handleAddStock = async () => {
    if (!stockModal || !addQty || Number(addQty) <= 0) { addToast('Enter valid qty', 'error'); return; }
    try {
      await addStock(stockModal.id, Number(addQty), 'Manual restock');
      refresh();
      addToast(`+${addQty} ${stockModal.unit} ΓåÆ ${stockModal.name}`, 'success');
      setStockModal(null);
      setAddQty('');
    } catch (e) { addToast('Failed: ' + e.message, 'error'); }
  };

  const openAddItem = (type) => {
    const typeCats = type === 'bar' ? barCats : kitchenCats;
    setNewItemForm({
      name: '', code: `ITM${Date.now().toString().slice(-4)}`,
      price: '', categoryId: typeCats[0]?.id || '',
      stock: '50', unit: type === 'bar' ? 'bottle' : 'plate', isVeg: true,
    });
    setAddItemModal(type);
  };

  const handleAddNewItem = async () => {
    if (!newItemForm.name || !newItemForm.price) { addToast('Name & Price required', 'error'); return; }
    try {
      await addMenuItem({
        ...newItemForm,
        price: Number(newItemForm.price),
        stock: Number(newItemForm.stock) || 0,
      });
      refresh();
      addToast(`${newItemForm.name} added`, 'success');
      setAddItemModal(null);
    } catch (e) { addToast('Failed', 'error'); }
  };

  // Category handlers
  const openCatNew = (type) => {
    setCatForm({ name: '', color: type === 'bar' ? '#6C5CE7' : '#FDCB6E', icon: type === 'bar' ? '≡ƒì╕' : '≡ƒì╜∩╕Å', shortcut: '', type });
    setCatModal('new');
  };
  const openCatEdit = (cat) => {
    setCatForm({ name: cat.name, color: cat.color, icon: cat.icon, shortcut: cat.shortcut || '', type: cat.type || 'bar' });
    setCatModal(cat);
  };
  const handleSaveCat = async () => {
    if (!catForm.name) { addToast('Name required', 'error'); return; }
    try {
      if (catModal === 'new') { await addCategory(catForm); addToast('Category added', 'success'); }
      else { await updateCategory(catModal.id, catForm); addToast('Category updated', 'success'); }
      refresh();
      setCatModal(null);
    } catch (e) { addToast('Failed', 'error'); }
  };
  const handleDeleteCat = async (id) => {
    if (confirm('Delete this category?')) {
      try { await deleteCategory(id); refresh(); addToast('Deleted', 'info'); }
      catch (e) { addToast('Failed', 'error'); }
    }
  };

  // Render stock table
  const renderStockTable = (items, emptyMsg) => (
    <table className="data-table">
      <thead>
        <tr>
          <th>ITEM</th>
          <th>CODE</th>
          <th>CATEGORY</th>
          <th>PRICE</th>
          <th>STOCK</th>
          <th>STATUS</th>
          <th>ACTION</th>
        </tr>
      </thead>
      <tbody>
        {items.map(item => {
          const cat = categories.find(c => c.id === item.categoryId);
          return (
            <tr key={item.id}>
              <td style={{ fontWeight: 600 }}>{item.name}</td>
              <td><code style={{ fontSize: '10px', padding: '1px 4px', background: 'var(--bg-tertiary)', borderRadius: '2px', fontFamily: 'var(--font-mono)' }}>{item.code}</code></td>
              <td style={{ fontSize: '11px', color: 'var(--text-secondary)' }}>{cat?.icon} {cat?.name || 'ΓÇö'}</td>
              <td style={{ fontWeight: 700, fontFamily: 'var(--font-mono)' }}>{config.currency}{item.price}</td>
              <td>
                <div className="stock-indicator">
                  <div className="stock-bar">
                    <div
                      className={`stock-bar-fill ${item.stock > 30 ? 'high' : item.stock > 10 ? 'medium' : 'low'}`}
                      style={{ width: `${Math.min(100, (item.stock / 100) * 100)}%` }}
                    />
                  </div>
                  <span style={{ fontSize: '11px', fontWeight: 700, fontFamily: 'var(--font-mono)' }}>{item.stock}</span>
                </div>
              </td>
              <td>
                {item.stock <= 0 ? <span className="badge badge-danger">OUT</span>
                  : item.stock <= 10 ? <span className="badge badge-warning">LOW</span>
                  : <span className="badge badge-success">OK</span>}
              </td>
              <td>
                <button className="btn btn-sm btn-primary" onClick={() => { setStockModal(item); setAddQty(''); }}>
                  <Plus size={10} /> ADD
                </button>
              </td>
            </tr>
          );
        })}
        {items.length === 0 && (
          <tr><td colSpan="7" style={{ textAlign: 'center', padding: '20px', color: 'var(--text-tertiary)', fontSize: '11px' }}>{emptyMsg}</td></tr>
        )}
      </tbody>
    </table>
  );

  // Render category list for a type
  const renderCategoryList = (type) => {
    const cats = type === 'bar' ? barCats : kitchenCats;
    return (
      <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', padding: '6px 8px', background: 'var(--bg-tertiary)', borderBottom: '1px solid var(--border-color)' }}>
        {cats.map(cat => (
          <div key={cat.id} style={{
            display: 'flex', alignItems: 'center', gap: '4px', padding: '3px 8px',
            background: 'var(--bg-card)', border: '1px solid var(--border-color)',
            borderRadius: 'var(--radius-sm)', fontSize: '10px',
          }}>
            <span>{cat.icon}</span>
            <span style={{ fontWeight: 600 }}>{cat.name}</span>
            {isAdmin && (
              <>
                <button className="btn btn-ghost" style={{ padding: '1px', minHeight: 0 }} onClick={() => openCatEdit(cat)}>
                  <Edit3 size={9} />
                </button>
                <button className="btn btn-ghost" style={{ padding: '1px', minHeight: 0, color: 'var(--brand-danger)' }} onClick={() => handleDeleteCat(cat.id)}>
                  <Trash2 size={9} />
                </button>
              </>
            )}
          </div>
        ))}
        {isAdmin && (
          <button className="btn btn-sm btn-ghost" style={{ fontSize: '10px', padding: '3px 6px' }} onClick={() => openCatNew(type)}>
            <Plus size={9} /> Add
          </button>
        )}
      </div>
    );
  };

  return (
    <div className="page-content">
      <div className="page-header">
        <div className="page-title">
          <Package size={16} /> INVENTORY
          <span style={{ fontSize: '10px', color: 'var(--text-tertiary)', fontWeight: 500 }}>
            {menuItems.length} items ┬╖ {lowStockItems.length} low
          </span>
        </div>
        <div className="tabs" style={{ marginBottom: 0, border: 'none' }}>
          <button className={`tab ${activeTab === 'stock' ? 'active' : ''}`} onClick={() => setActiveTab('stock')}>STOCK</button>
          <button className={`tab ${activeTab === 'log' ? 'active' : ''}`} onClick={() => setActiveTab('log')}>LOG</button>
        </div>
      </div>

      {/* Low stock alert */}
      {lowStockItems.length > 0 && (
        <div className="low-stock-alert" style={{ marginBottom: '10px' }}>
          <AlertTriangle size={14} />
          <span>
            <b>{lowStockItems.length} LOW:</b>&nbsp;
            {lowStockItems.slice(0, 5).map(i => `${i.name}(${i.stock})`).join(', ')}
            {lowStockItems.length > 5 && ` +${lowStockItems.length - 5} more`}
          </span>
        </div>
      )}

      {activeTab === 'stock' && (
        <>
          {/* Single search bar */}
          <div className="search-input-wrapper" style={{ marginBottom: '12px', maxWidth: '400px' }}>
            <Search />
            <input className="input" placeholder="Search bar & kitchen items..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
          </div>

          {/* Horizontal split: BAR | KITCHEN */}
          <div className="inventory-split-container" style={{ 
            display: 'grid', 
            gridTemplateColumns: isBarEnabled && isKitchenEnabled ? '1fr 1fr' : '1fr', 
            gap: '12px' 
          }}>
            {/* BAR ITEMS SECTION */}
            {isBarEnabled && (
              <div className="inventory-section">
                <div className="inventory-section-header bar">
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <Wine size={16} />
                    <span className="inventory-section-title">{barLabel.toUpperCase()} ITEMS</span>
                    <span className="badge badge-info">{barItems.length + uncategorized.length}</span>
                  </div>
                  <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                    <span style={{ fontSize: '10px', fontFamily: 'var(--font-mono)', color: 'var(--text-tertiary)' }}>
                      {(barItems.concat(uncategorized)).filter(i => i.stock <= 10).length} low
                    </span>
                    {isAdmin && (
                      <button className="btn btn-sm btn-success" onClick={() => openAddItem('bar')}>
                        <PlusCircle size={10} /> ADD
                      </button>
                    )}
                  </div>
                </div>
                {renderCategoryList('bar')}
                <div className="inventory-section-body">
                  {renderStockTable([...barItems, ...uncategorized], searchQuery ? 'No items match' : 'No items')}
                </div>
              </div>
            )}

            {/* KITCHEN ITEMS SECTION */}
            {isKitchenEnabled && (
              <div className="inventory-section">
                <div className="inventory-section-header kitchen">
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <Coffee size={16} />
                    <span className="inventory-section-title">{kitchenLabel.toUpperCase()} ITEMS</span>
                    <span className="badge badge-warning">{kitchenItems.length}</span>
                  </div>
                  <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                    <span style={{ fontSize: '10px', fontFamily: 'var(--font-mono)', color: 'var(--text-tertiary)' }}>
                      {kitchenItems.filter(i => i.stock <= 10).length} low
                    </span>
                    {isAdmin && (
                      <button className="btn btn-sm btn-success" onClick={() => openAddItem('kitchen')}>
                        <PlusCircle size={10} /> ADD
                      </button>
                    )}
                  </div>
                </div>
                {renderCategoryList('kitchen')}
                <div className="inventory-section-body">
                  {renderStockTable(kitchenItems, searchQuery ? 'No items match' : 'No items')}
                </div>
              </div>
            )}
          </div>
        </>
      )}

      {activeTab === 'log' && (
        <div className="card">
          <div className="card-body" style={{ padding: 0, maxHeight: 'calc(100vh - 200px)', overflow: 'auto' }}>
            <table className="data-table">
              <thead>
                <tr><th>ITEM</th><th>TYPE</th><th>QTY</th><th>REMAINING</th><th>TIME</th></tr>
              </thead>
              <tbody>
                {inventoryLog.map(log => (
                  <tr key={log.id}>
                    <td style={{ fontWeight: 600 }}>{log.itemName}</td>
                    <td>
                      {log.type === 'add'
                        ? <span className="badge badge-success">+ADD</span>
                        : <span className="badge badge-danger">-USE</span>}
                    </td>
                    <td style={{ fontWeight: 700, fontFamily: 'var(--font-mono)' }}>{log.quantity}</td>
                    <td style={{ fontFamily: 'var(--font-mono)' }}>{log.remainingStock}</td>
                    <td style={{ color: 'var(--text-tertiary)', fontSize: '10px' }}>{new Date(log.timestamp).toLocaleString()}</td>
                  </tr>
                ))}
                {inventoryLog.length === 0 && (
                  <tr><td colSpan="5" style={{ textAlign: 'center', padding: '32px', color: 'var(--text-tertiary)' }}>No activity</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Add Stock Modal */}
      {stockModal && (
        <div className="modal-backdrop" onClick={() => setStockModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">ADD STOCK ΓÇö {stockModal.name}</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setStockModal(null)}>Γ£ò</button>
            </div>
            <div className="modal-body">
              <p style={{ marginBottom: '8px', color: 'var(--text-secondary)', fontSize: '11px', fontFamily: 'var(--font-mono)' }}>
                Current: <b>{stockModal.stock} {stockModal.unit}</b>
              </p>
              <div className="input-group">
                <label className="input-label">Quantity to Add</label>
                <input
                  type="number" className="input" value={addQty}
                  onChange={e => setAddQty(e.target.value)}
                  placeholder="Enter qty" autoFocus min="1"
                  onKeyDown={e => { if (e.key === 'Enter') handleAddStock(); }}
                />
              </div>
              <div style={{ display: 'flex', gap: '4px', marginTop: '8px' }}>
                {[5, 10, 20, 50, 100].map(n => (
                  <button key={n} className="btn btn-sm btn-secondary" onClick={() => setAddQty(String(n))}>+{n}</button>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setStockModal(null)}>Cancel</button>
              <button className="btn btn-success" onClick={handleAddStock}>ADD STOCK</button>
            </div>
          </div>
        </div>
      )}

      {/* Add New Item Modal */}
      {addItemModal && (
        <div className="modal-backdrop" onClick={() => setAddItemModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">
                ADD {addItemModal === 'bar' ? barLabel.toUpperCase() : kitchenLabel.toUpperCase()} ITEM
              </h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setAddItemModal(null)}>Γ£ò</button>
            </div>
            <div className="modal-body">
              <div className="config-grid">
                <div className="input-group">
                  <label className="input-label">Item Name *</label>
                  <input className="input" value={newItemForm.name}
                    onChange={e => setNewItemForm(f => ({ ...f, name: e.target.value }))}
                    placeholder="e.g. Item Name" autoFocus />
                </div>
                <div className="input-group">
                  <label className="input-label">Code</label>
                  <input className="input" value={newItemForm.code}
                    onChange={e => setNewItemForm(f => ({ ...f, code: e.target.value }))}
                    placeholder="e.g. ITM01" />
                </div>
                <div className="input-group">
                  <label className="input-label">Price ({config.currency}) *</label>
                  <input type="number" className="input" value={newItemForm.price}
                    onChange={e => setNewItemForm(f => ({ ...f, price: e.target.value }))}
                    placeholder="0" />
                </div>
                <div className="input-group">
                  <label className="input-label">Category</label>
                  <select className="select" value={newItemForm.categoryId}
                    onChange={e => setNewItemForm(f => ({ ...f, categoryId: e.target.value }))}>
                    {(addItemModal === 'bar' ? barCats : kitchenCats).map(c => (
                      <option key={c.id} value={c.id}>{c.icon} {c.name}</option>
                    ))}
                  </select>
                </div>
                <div className="input-group">
                  <label className="input-label">Initial Stock</label>
                  <input type="number" className="input" value={newItemForm.stock}
                    onChange={e => setNewItemForm(f => ({ ...f, stock: e.target.value }))}
                    placeholder="0" />
                </div>
                <div className="input-group">
                  <label className="input-label">Unit</label>
                  <select className="select" value={newItemForm.unit}
                    onChange={e => setNewItemForm(f => ({ ...f, unit: e.target.value }))}>
                    {addItemModal === 'bar' ? (
                      <>
                        <option value="bottle">Bottle</option>
                        <option value="peg">Peg</option>
                        <option value="glass">Glass</option>
                        <option value="can">Can</option>
                        <option value="pitcher">Pitcher</option>
                        <option value="shot">Shot</option>
                        <option value="session">Session</option>
                        <option value="piece">Piece</option>
                      </>
                    ) : (
                      <>
                        <option value="plate">Plate</option>
                        <option value="piece">Piece</option>
                        <option value="kg">Kg</option>
                        <option value="liter">Liter</option>
                        <option value="cup">Cup</option>
                        <option value="bottle">Bottle</option>
                      </>
                    )}
                  </select>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setAddItemModal(null)}>Cancel</button>
              <button className="btn btn-success" onClick={handleAddNewItem}>ADD TO INVENTORY</button>
            </div>
          </div>
        </div>
      )}

      {/* Category Modal */}
      {catModal && (
        <div className="modal-backdrop" onClick={() => setCatModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{catModal === 'new' ? 'ADD CATEGORY' : 'EDIT CATEGORY'}</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setCatModal(null)}>Γ£ò</button>
            </div>
            <div className="modal-body">
              <div className="input-group"><label className="input-label">Name *</label>
                <input className="input" value={catForm.name} onChange={e => setCatForm(f => ({ ...f, name: e.target.value }))} autoFocus /></div>
              <div className="input-group"><label className="input-label">Icon (Emoji)</label>
                <input className="input" value={catForm.icon} onChange={e => setCatForm(f => ({ ...f, icon: e.target.value }))} /></div>
              <div className="input-group"><label className="input-label">Type</label>
                <select className="select" value={catForm.type} onChange={e => setCatForm(f => ({ ...f, type: e.target.value }))}>
                  <option value="bar">{barLabel}</option>
                  <option value="kitchen">{kitchenLabel}</option>
                </select></div>
              <div className="input-group"><label className="input-label">Color</label>
                <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                  <input type="color" value={catForm.color} onChange={e => setCatForm(f => ({ ...f, color: e.target.value }))}
                    style={{ width: '40px', height: '32px', border: 'none', cursor: 'pointer', borderRadius: '4px' }} />
                  <input className="input" value={catForm.color} onChange={e => setCatForm(f => ({ ...f, color: e.target.value }))} style={{ width: '100px' }} />
                </div></div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setCatModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={handleSaveCat}>{catModal === 'new' ? 'ADD' : 'SAVE'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useMemo, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp, useToast } from '../context/AppContext';
import {
  getOrderForTable, addItemToOrder, updateOrderItem, removeOrderItem,
  createOrder, generateBill, cancelOrder
} from '../store/data';
import { printSplitKOT, printKitchenKOT, printBarKOT, printBillDirect } from '../utils/print';
import { Search, ArrowLeft, Plus, Minus, Trash2, StickyNote, Printer, Wine, Coffee, CreditCard, Banknote, Smartphone, Receipt } from 'lucide-react';

export default function OrderPage() {
  const { tableId } = useParams();
  const navigate = useNavigate();
  const { tables = [], menuItems = [], categories = [], config = {}, refresh, currentUser } = useApp();
  const { addToast } = useToast();
  const isAdmin = currentUser?.role === 'admin';

  const table = useMemo(() => (tables || []).find(t => t.id === tableId), [tables, tableId]);
  const [order, setOrder] = useState(null);
  const [barCategory, setBarCategory] = useState('all');
  const [kitchenCategory, setKitchenCategory] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [noteModal, setNoteModal] = useState(null);
  const [noteText, setNoteText] = useState('');
  const [showKOTMenu, setShowKOTMenu] = useState(false);
  const [directBillModal, setDirectBillModal] = useState(false);
  const [paymentMode, setPaymentMode] = useState('Cash');
  const [discount, setDiscount] = useState(0);
  const [busy, setBusy] = useState(false);
  const [orderLoading, setOrderLoading] = useState(true);

  // Load order on mount
  const loadOrder = useCallback(async () => {
    if (!tableId) return;
    try {
      let existingOrder = await getOrderForTable(tableId);
      if (!existingOrder && table?.status === 'available') {
        await createOrder(tableId, table.label || `T${table.number}`);
        existingOrder = await getOrderForTable(tableId);
        refresh();
      }
      setOrder(existingOrder);
    } catch (e) {
      console.error('Load order error:', e);
      addToast('Order loading failed: ' + (e.message || 'Unknown'), 'error');
      setOrder(null);
    } finally {
      setOrderLoading(false);
    }
  }, [tableId, table]);

  useEffect(() => { loadOrder(); }, [loadOrder]);

  const safeItems = order?.items || [];

  const isKitchenEnabled = config.isKitchenEnabled !== false;
  const isBarEnabled = config.isBarEnabled !== false;
  const barLabel = config.barLabel || 'Bar';
  const kitchenLabel = config.kitchenLabel || 'Kitchen';

  // Classify categories
  const barCategories = useMemo(() => (categories || []).filter(c => c.type === 'bar'), [categories]);
  const kitchenCategories = useMemo(() => (categories || []).filter(c => c.type === 'kitchen'), [categories]);
  const barCatIds = useMemo(() => barCategories.map(c => c.id), [barCategories]);
  const kitchenCatIds = useMemo(() => kitchenCategories.map(c => c.id), [kitchenCategories]);

  // Filter items
  const isSearching = searchQuery.length > 0;
  const q = searchQuery.toLowerCase();

  const barItems = useMemo(() => {
    if (!isBarEnabled) return [];
    let items = (menuItems || []).filter(i => barCatIds.includes(i.categoryId));
    if (barCategory !== 'all') items = items.filter(i => i.categoryId === barCategory);
    if (isSearching) items = items.filter(i => i.name?.toLowerCase().includes(q) || i.code?.toLowerCase()?.includes(q));
    return items;
  }, [menuItems, barCategory, searchQuery, barCatIds, isBarEnabled]);

  const kitchenItems = useMemo(() => {
    if (!isKitchenEnabled) return [];
    let items = (menuItems || []).filter(i => kitchenCatIds.includes(i.categoryId));
    if (kitchenCategory !== 'all') items = items.filter(i => i.categoryId === kitchenCategory);
    if (isSearching) items = items.filter(i => i.name?.toLowerCase().includes(q) || i.code?.toLowerCase()?.includes(q));
    return items;
  }, [menuItems, kitchenCategory, searchQuery, kitchenCatIds, isKitchenEnabled]);

  const handleAddItem = async (menuItem) => {
    if (!order) { addToast("Order not initialized yet", "warning"); return; }
    if (busy) return;
    setBusy(true);
    try {
      const cat = (categories || []).find(c => c.id === menuItem.categoryId);
      await addItemToOrder(order.id, { ...menuItem, categoryType: cat?.type || 'bar' });
      await loadOrder();
      addToast(`+ ${menuItem.name}`, 'success');
    } catch (e) { addToast(e.message || 'Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleQtyChange = async (itemId, delta) => {
    if (!order || busy) return;
    const item = safeItems.find(i => i.id === itemId);
    if (!item) return;
    const newQty = item.quantity + delta;
    setBusy(true);
    try {
      if (newQty <= 0) await removeOrderItem(order.id, itemId);
      else await updateOrderItem(order.id, itemId, { quantity: newQty });
      await loadOrder();
    } catch (e) { addToast('Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleRemoveItem = async (itemId) => {
    if (!order || busy) return;
    setBusy(true);
    try { await removeOrderItem(order.id, itemId); await loadOrder(); }
    catch (e) { addToast('Failed', 'error'); }
    finally { setBusy(false); }
  };

  const handleAddNote = async () => {
    if (!order || !noteModal || busy) return;
    setBusy(true);
    try { await updateOrderItem(order.id, noteModal.id, { note: noteText }); await loadOrder(); }
    catch (e) { addToast('Failed', 'error'); }
    finally { setBusy(false); }
    setNoteModal(null);
    setNoteText('');
  };

  const handleGoToBilling = async () => {
    if (!order || safeItems.length === 0) { addToast('Add items first', 'warning'); return; }
    if (busy) return;
    setBusy(true);
    try {
      await refresh();
      navigate(`/billing/${order.id}`);
    } finally {
      setBusy(false);
    }
  };

  // KOT print
  const handlePrintSplitKOT = () => {
    if (!order || safeItems.length === 0) { addToast('No items', 'warning'); return; }
    try {
      const tableLabel = table?.label || table?.number;
      // Pass config to help printer use correct labels
      const result = printSplitKOT(order, tableLabel, categories, config);
      if (result?.kitchenKOT && result?.barKOT) addToast(`${kitchenLabel} KOT + ${barLabel} KOT printed`, 'success');
      else if (result?.kitchenKOT) addToast(`${kitchenLabel} KOT printed`, 'success');
      else if (result?.barKOT) addToast(`${barLabel} KOT printed`, 'success');
      else addToast('KOT sent', 'success');
    } catch (e) { addToast('Print failed', 'error'); }
    setShowKOTMenu(false);
  };

  const handlePrintKitchenOnly = () => {
    if (!order) return;
    try {
      const tableLabel = table?.label || table?.number;
      const success = printKitchenKOT(order, tableLabel, categories, config);
      addToast(success ? `${kitchenLabel} KOT printed` : `No ${kitchenLabel} items`, success ? 'success' : 'warning');
    } catch (e) { addToast('Print failed', 'error'); }
    setShowKOTMenu(false);
  };

  const handlePrintBarOnly = () => {
    if (!order) return;
    try {
      const tableLabel = table?.label || table?.number;
      const success = printBarKOT(order, tableLabel, categories, config);
      addToast(success ? `${barLabel} KOT printed` : `No ${barLabel} items`, success ? 'success' : 'warning');
    } catch (e) { addToast('Print failed', 'error'); }
    setShowKOTMenu(false);
  };

  // Direct bill
  const handleCancelOrder = async () => {
    if (!order || busy) return;
    if (!window.confirm('Cancel this order and free the table?')) return;
    setBusy(true);
    try {
      await cancelOrder(order.id, table.id);
      await refresh();
      addToast('Order cancelled', 'info');
      navigate('/tables');
    } catch (e) {
      addToast('Failed: ' + (e.message || ''), 'error');
    } finally {
      setBusy(false);
    }
  };

  const handleDirectBill = async () => {
    if (!order || safeItems.length === 0 || busy) return;
    setBusy(true);
    try {
      const result = await generateBill(order.id, paymentMode, discount);
      if (result?.bill) {
        try { printBillDirect({ ...result.bill, currency: config.currency }); } catch {}
        await refresh();
        addToast('Direct bill generated & printed', 'success');
        setDirectBillModal(false);
        navigate('/tables');
      } else {
        addToast('Failed to generate bill', 'error');
      }
    } catch (e) { addToast('Failed: ' + (e.message || ''), 'error'); }
    finally { setBusy(false); }
  };

  const subtotal = safeItems.reduce((s, i) => s + ((i.price || 0) * (i.quantity || 0)), 0);
  const tax = (subtotal * (config.taxRate || 0)) / 100;
  const serviceCharge = (subtotal * (config.serviceChargeRate || 0)) / 100;
  const total = subtotal + tax + serviceCharge;
  const kitchenCount = safeItems.filter(i => i.categoryType === 'kitchen').length;
  const barCount = safeItems.filter(i => i.categoryType !== 'kitchen').length;

  if (!table && !orderLoading) {
    return (
      <div className="page-content">
        <div className="empty-state">
          <p className="empty-state-title">Table not found</p>
          <button className="btn btn-primary" onClick={() => navigate('/tables')}>Back</button>
        </div>
      </div>
    );
  }

  if (orderLoading) {
    return (
      <div className="page-content">
        <div className="resto-loader">
          <div className="resto-logo-spin">RG</div>
          <div className="resto-loader-text">Loading order...</div>
        </div>
      </div>
    );
  }

  const renderItemCard = (item) => {
    // Only gray out if they are actively using stock tracking (e.g. stock <= 0 and they manually manage it)
    // To prevent false blockages, we won't block clicking here anymore.
    const isOOS = false; // Bypass visual OOS for now so users can select unconditionally
    return (
      <div
        key={item.id}
        className="menu-item-card"
        onClick={() => !isOOS && handleAddItem(item)}
        style={{
          opacity: isOOS ? 0.25 : busy ? 0.6 : 1,
          pointerEvents: isOOS || busy ? 'none' : 'auto',
          filter: isOOS ? 'grayscale(1)' : undefined,
        }}
      >
        <div className="menu-item-name">{item.name}</div>
        {item.code && <div className="menu-item-code">{item.code}</div>}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 'auto', paddingTop: '4px' }}>
          <div className="menu-item-price">{config.currency}{item.price}</div>
          {item.stock !== undefined && item.stock !== null && item.stock <= 5 && item.stock > 0 && (
            <span style={{ fontSize: '9px', color: 'var(--brand-danger)', fontFamily: 'var(--font-mono)' }}>LOW:{item.stock}</span>
          )}
          {isOOS && <span className="badge badge-danger">OUT</span>}
        </div>
      </div>
    );
  };

  return (
    <div className="order-layout">
      {/* Left: Menu */}
      <div className="menu-panel">
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <button className="btn btn-ghost btn-icon" onClick={() => navigate('/tables')} title="Back">
            <ArrowLeft size={16} />
          </button>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 800, fontFamily: 'var(--font-mono)', fontSize: '13px' }}>
              {table?.label || `T${table?.number}`} {table?.customerName && `ΓÇö ${table.customerName}`}
            </div>
          </div>
          <div style={{ position: 'relative' }}>
            <button className="btn btn-sm btn-secondary" onClick={() => setShowKOTMenu(!showKOTMenu)} title="Print KOT">
              <Printer size={12} /> KOT Γû╛
            </button>
            {showKOTMenu && (
              <div className="kot-dropdown" style={{ minWidth: '200px' }}>
                <button className="kot-dropdown-item" onClick={handlePrintSplitKOT}>
                  <Printer size={12} /> <span>Print All KOT</span>
                  <span className="kot-dropdown-sub">Split autoΓÇædetect</span>
                </button>
                {isKitchenEnabled && (
                  <button className="kot-dropdown-item kitchen" onClick={handlePrintKitchenOnly}>
                    <Coffee size={12} /> <span>{kitchenLabel} KOT Only</span>
                    <span className="kot-dropdown-sub">{kitchenCount} items</span>
                  </button>
                )}
                {isBarEnabled && (
                  <button className="kot-dropdown-item bar" onClick={handlePrintBarOnly}>
                    <Wine size={12} /> <span>{barLabel} KOT Only</span>
                    <span className="kot-dropdown-sub">{barCount} items</span>
                  </button>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="search-input-wrapper">
          <Search />
          <input className="input" placeholder="Search all items..." value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') {
                const allResults = [...barItems, ...kitchenItems];
                if (allResults.length === 1) { handleAddItem(allResults[0]); setSearchQuery(''); }
              }
              if (e.key === 'Escape') { setSearchQuery(''); e.target.blur(); }
            }}
          />
        </div>

        <div className="menu-split-container" style={{ 
          display: 'grid', 
          gridTemplateColumns: isBarEnabled && isKitchenEnabled ? '1fr 1fr' : '1fr', 
          gap: '12px' 
        }}>
          {isBarEnabled && (
            <div className="menu-split-section bar">
              <div className="menu-split-header bar">
                <Wine size={14} />
                <span>{barLabel.toUpperCase()}</span>
                <span style={{ fontSize: '9px', opacity: 0.6 }}>{barItems.length}</span>
              </div>
              {!isSearching && (
                <div className="category-tabs compact">
                  <button className={`category-tab ${barCategory === 'all' ? 'active' : ''}`} onClick={() => setBarCategory('all')}>ALL</button>
                  {barCategories.map(cat => (
                    <button key={cat.id} className={`category-tab ${barCategory === cat.id ? 'active' : ''}`} onClick={() => setBarCategory(cat.id)}>
                      {cat.icon} {cat.name}
                    </button>
                  ))}
                </div>
              )}
              <div className="menu-items-grid compact">
                {barItems.map(renderItemCard)}
                {barItems.length === 0 && <div className="empty-state" style={{ gridColumn: '1/-1', padding: '12px' }}><p className="empty-state-text" style={{ fontSize: '10px' }}>No items</p></div>}
              </div>
            </div>
          )}

          {isKitchenEnabled && (
            <div className="menu-split-section kitchen">
              <div className="menu-split-header kitchen">
                <Coffee size={14} />
                <span>{kitchenLabel.toUpperCase()}</span>
                <span style={{ fontSize: '9px', opacity: 0.6 }}>{kitchenItems.length}</span>
              </div>
              {!isSearching && (
                <div className="category-tabs compact">
                  <button className={`category-tab ${kitchenCategory === 'all' ? 'active' : ''}`} onClick={() => setKitchenCategory('all')}>ALL</button>
                  {kitchenCategories.map(cat => (
                    <button key={cat.id} className={`category-tab ${kitchenCategory === cat.id ? 'active' : ''}`} onClick={() => setKitchenCategory(cat.id)}>
                      {cat.icon} {cat.name}
                    </button>
                  ))}
                </div>
              )}
              <div className="menu-items-grid compact">
                {kitchenItems.map(renderItemCard)}
                {kitchenItems.length === 0 && <div className="empty-state" style={{ gridColumn: '1/-1', padding: '12px' }}><p className="empty-state-text" style={{ fontSize: '10px' }}>No items</p></div>}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Right: Order Panel */}
      <div className="order-panel">
        <div className="order-panel-header">
          <span style={{ fontWeight: 700, fontFamily: 'var(--font-mono)', fontSize: '12px' }}>ORDER</span>
          <span className="badge badge-info">{safeItems.length} items</span>
        </div>

        <div className="order-items-list">
          {safeItems.length > 0 ? (
            safeItems.map(item => (
              <div key={item.id} className="order-item">
                <div className="order-item-info">
                  <div className="order-item-name">
                    {item.name}
                    <span style={{
                      fontSize: '8px', marginLeft: '4px', padding: '1px 3px',
                      borderRadius: '2px', fontWeight: 700,
                      background: item.categoryType === 'kitchen' ? 'rgba(253, 203, 110, 0.2)' : 'rgba(108, 92, 231, 0.2)',
                      color: item.categoryType === 'kitchen' ? 'var(--brand-warning)' : 'var(--brand-primary-light)',
                    }}>
                      {item.categoryType === 'kitchen' ? 'K' : 'B'}
                    </span>
                  </div>
                  {item.note && <div className="order-item-note">ΓåÆ {item.note}</div>}
                </div>
                <div className="qty-controls">
                  <button className="qty-btn" onClick={() => handleQtyChange(item.id, -1)} disabled={busy}><Minus size={10} /></button>
                  <span className="qty-value">{item.quantity}</span>
                  <button className="qty-btn" onClick={() => handleQtyChange(item.id, 1)} disabled={busy}><Plus size={10} /></button>
                </div>
                <div className="order-item-price">{config.currency}{(item.price || 0) * (item.quantity || 0)}</div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1px' }}>
                  <button className="btn btn-ghost btn-sm" onClick={() => { setNoteModal(item); setNoteText(item.note || ''); }}>
                    <StickyNote size={10} />
                  </button>
                  <button className="btn btn-ghost btn-sm" style={{ color: 'var(--brand-danger)' }} onClick={() => handleRemoveItem(item.id)} disabled={busy}>
                    <Trash2 size={10} />
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div className="empty-state">
              <p className="empty-state-title" style={{ fontSize: '11px' }}>Empty</p>
              <p className="empty-state-text">Click items to add</p>
            </div>
          )}
        </div>

        {/* Order Actions */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '8px', padding: '12px' }}>
          {safeItems.length > 0 && (
            <div className="order-actions" style={{ gridTemplateColumns: isAdmin ? '1fr 1fr 1fr' : '1fr 1fr', gap: '8px', marginBottom: '8px' }}>
              <button className="btn btn-secondary btn-lg" onClick={handlePrintSplitKOT}><Printer size={14} /> KOT</button>
              {isAdmin && (
                <button className="btn btn-warning btn-lg" onClick={() => setDirectBillModal(true)} title="Direct bill without KOT">
                  <Receipt size={14} /> DIRECT
                </button>
              )}
              <button className="btn btn-success btn-lg" onClick={handleGoToBilling}>BILL</button>
            </div>
          )}
          <button className="btn btn-ghost" style={{ color: 'var(--brand-danger)', width: '100%' }} onClick={handleCancelOrder} disabled={busy}>
             CANCEL ORDER
          </button>
        </div>
      </div>

      {/* Note Modal */}
      {noteModal && (
        <div className="modal-backdrop" onClick={() => setNoteModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">NOTE ΓÇö {noteModal.name}</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setNoteModal(null)}>Γ£ò</button>
            </div>
            <div className="modal-body">
              <textarea className="input" placeholder="e.g., No ice, extra lime..." value={noteText}
                onChange={e => setNoteText(e.target.value)} rows={2} autoFocus
                onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleAddNote(); } }}
              />
              <div style={{ display: 'flex', gap: '4px', marginTop: '8px', flexWrap: 'wrap' }}>
                {['No ice', 'Extra lime', 'On the rocks', 'Neat', 'With soda', 'Double'].map(q => (
                  <button key={q} className="btn btn-sm btn-secondary" onClick={() => setNoteText(prev => prev ? `${prev}, ${q}` : q)}>{q}</button>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setNoteModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={handleAddNote} disabled={busy}>Save</button>
            </div>
          </div>
        </div>
      )}

      {/* Direct Bill Modal */}
      {directBillModal && (
        <div className="modal-backdrop" onClick={() => setDirectBillModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">DIRECT BILL ΓÇö No KOT</h3>
              <button className="btn btn-ghost btn-icon" onClick={() => setDirectBillModal(false)}>Γ£ò</button>
            </div>
            <div className="modal-body">
              <p style={{ fontSize: '11px', color: 'var(--text-secondary)', marginBottom: '12px' }}>
                Generate bill directly without printing KOT. Ideal for counter items and takeaway.
              </p>
              <div style={{ marginBottom: '12px', maxHeight: '150px', overflow: 'auto', background: 'var(--bg-tertiary)', borderRadius: 'var(--radius-md)', padding: '8px' }}>
                {safeItems.map(item => (
                  <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '2px 0', fontSize: '11px' }}>
                    <span>{item.name} ├ù{item.quantity}</span>
                    <span style={{ fontFamily: 'var(--font-mono)', fontWeight: 600 }}>{config.currency}{(item.price || 0) * (item.quantity || 0)}</span>
                  </div>
                ))}
              </div>
              <div style={{ fontSize: '11px', fontWeight: 700, fontFamily: 'var(--font-mono)', marginBottom: '8px', color: 'var(--text-secondary)' }}>PAYMENT</div>
              <div className="payment-modes" style={{ marginBottom: '12px' }}>
                {[{ mode: 'Cash', icon: Banknote }, { mode: 'Card', icon: CreditCard }, { mode: 'UPI', icon: Smartphone }].map(p => (
                  <button key={p.mode} className={`payment-mode-btn ${paymentMode === p.mode ? 'active' : ''}`}
                    onClick={() => setPaymentMode(p.mode)}><p.icon size={18} /><span>{p.mode}</span></button>
                ))}
              </div>
              <div className="input-group">
                <label className="input-label">Discount (%)</label>
                <input type="number" className="input" value={discount}
                  onChange={e => setDiscount(Math.max(0, Math.min(100, Number(e.target.value) || 0)))} min="0" max="100" />
              </div>
              <div className="order-summary-row total" style={{ marginTop: '8px' }}>
                <span>TOTAL</span>
                <span>{config.currency}{Math.round(total - (subtotal * discount / 100))}</span>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setDirectBillModal(false)}>Cancel</button>
              <button className="btn btn-success btn-lg" onClick={handleDirectBill} disabled={busy}>
                <Receipt size={14} /> {busy ? 'GENERATING...' : 'GENERATE & PRINT'}
              </button>
            </div>
          </div>
        </div>
      )}

      {showKOTMenu && <div style={{ position: 'fixed', inset: 0, zIndex: 99 }} onClick={() => setShowKOTMenu(false)} />}
    </div>
  );
}

import { useApp } from '../context/AppContext';
import { useNavigate } from 'react-router-dom';
import { ClipboardList, Clock, CheckCircle } from 'lucide-react';

export default function OrdersListPage() {
  const { orders = [], config = {}, refreshing = false } = useApp();
  const navigate = useNavigate();

  const activeOrders = (orders || []).filter(o => o.status === 'active');
  const completedOrders = (orders || []).filter(o => o.status === 'completed').reverse().slice(0, 30);

  return (
    <div className="page-content">
      <div className="page-header">
        <div className="page-title">
          <ClipboardList size={16} /> ORDERS
          <span style={{ fontSize: '10px', color: 'var(--text-tertiary)', fontWeight: 500 }}>
            {activeOrders.length} active
          </span>
        </div>
      </div>

      <div style={{ marginBottom: '16px' }}>
        <div style={{ fontSize: '11px', fontWeight: 700, color: 'var(--text-secondary)', marginBottom: '8px', fontFamily: 'var(--font-mono)', display: 'flex', alignItems: 'center', gap: '6px' }}>
          <Clock size={12} color="var(--brand-primary)" /> ACTIVE
        </div>
        {activeOrders.length > 0 ? (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '8px' }}>
            {activeOrders.map(order => {
              const subtotal = (order.items || []).reduce((s, i) => s + ((i.price || 0) * (i.quantity || 0)), 0);
              return (
                <div key={order.id} className="card" style={{ cursor: 'pointer' }} onClick={() => navigate(`/order/${order.tableId}`)}>
                  <div className="card-body" style={{ padding: '10px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
                      <span style={{ fontWeight: 800, fontFamily: 'var(--font-mono)', fontSize: '13px' }}>T{order.tableNumber}</span>
                      <span className="badge badge-info">ACTIVE</span>
                    </div>
                    <div style={{ fontSize: '10px', color: 'var(--text-secondary)', fontFamily: 'var(--font-mono)' }}>
                      {(order.items || []).length} items ┬╖ {config.currency}{subtotal}
                    </div>
                    <div style={{ fontSize: '9px', color: 'var(--text-tertiary)', marginTop: '4px' }}>
                      {(order.items || []).slice(0, 3).map(i => `${i.name}├ù${i.quantity}`).join(', ')}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="card"><div className="empty-state" style={{ padding: '20px' }}>
            <p className="empty-state-text">No active orders</p>
          </div></div>
        )}
      </div>

      <div style={{ fontSize: '11px', fontWeight: 700, color: 'var(--text-secondary)', marginBottom: '8px', fontFamily: 'var(--font-mono)', display: 'flex', alignItems: 'center', gap: '6px' }}>
        <CheckCircle size={12} color="var(--brand-success)" /> COMPLETED
      </div>
      <div className="card">
        <div className="card-body" style={{ padding: 0, maxHeight: '400px', overflow: 'auto' }}>
          <table className="data-table">
            <thead><tr><th>TABLE</th><th>ITEMS</th><th>CUSTOMER</th><th>TIME</th></tr></thead>
            <tbody>
              {completedOrders.map(order => (
                <tr key={order.id}>
                  <td style={{ fontWeight: 700, fontFamily: 'var(--font-mono)' }}>T{order.tableNumber}</td>
                  <td>{(order.items || []).length}</td>
                  <td>{order.customerName || 'ΓÇö'}</td>
                  <td style={{ fontSize: '10px', color: 'var(--text-tertiary)' }}>{new Date(order.createdAt || order.created_at).toLocaleString()}</td>
                </tr>
              ))}
              {completedOrders.length === 0 && (
                <tr><td colSpan="4" style={{ textAlign: 'center', padding: '24px', color: 'var(--text-tertiary)' }}>None yet</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useApp } from '../context/AppContext';
import { getBills, getCategories, getSplitReport, getMonthBills, getMostSoldLiquor, getSessions, getSessionBills } from '../store/data';
import { TrendingUp, Calendar, DollarSign, PieChart, Printer, Wine, Coffee, Award } from 'lucide-react';

export default function ReportsPage() {
  const { config = {}, categories = [], bills = [], sessions = [], refreshing = false } = useApp();
  const [reportType, setReportType] = useState('daily'); // daily, monthly, session
  const [selectedMonth, setSelectedMonth] = useState(() => new Date().toISOString().slice(0, 7));
  const [selectedSessionId, setSelectedSessionId] = useState('');
  
  const today = new Date().toISOString().split('T')[0];
  
  // Get filtered bills based on report type
  let filteredBills = [];
  let reportLabel = '';
  if (reportType === 'daily') {
    filteredBills = (bills || []).filter(b => {
      const d = b.createdAt || b.created_at;
      return d?.startsWith(today);
    });
    reportLabel = `Today ΓÇö ${new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}`;
  } else if (reportType === 'monthly') {
    filteredBills = getMonthBills(selectedMonth, bills || []);
    const [y, m] = selectedMonth.split('-');
    reportLabel = `${new Date(Number(y), Number(m) - 1).toLocaleDateString('en-IN', { month: 'long', year: 'numeric' })}`;
  } else if (reportType === 'session' && selectedSessionId) {
    const s = sessions.find(se => se.id === selectedSessionId);
    filteredBills = getSessionBills(s, bills);
    reportLabel = s ? `Session: ${s.date} (${s.startedBy})` : '';
  }

  // KPI Calculations
  const totalRevenue = filteredBills.reduce((s, b) => s + (b.total || 0), 0);
  const totalBills = filteredBills.length;
  const totalItems = filteredBills.reduce((s, b) => s + (b.items || []).reduce((ss, i) => ss + (i.quantity || 0), 0), 0);
  
  // Split Report: bar vs kitchen
  const splitReport = getSplitReport(filteredBills, categories, config);

  // Payment Breakdown
  const paymentSales = { Cash: 0, Card: 0, UPI: 0 };
  filteredBills.forEach(bill => {
    if (paymentSales[bill.paymentMode] !== undefined) {
      paymentSales[bill.paymentMode] += bill.total;
    } else {
      paymentSales.Cash += bill.total;
    }
  });

  // Monthly most sold liquor
  const mostSoldLiquor = reportType === 'monthly' ? getMostSoldLiquor(selectedMonth, bills, categories) : [];

  // Category Breakdown
  const categorySales = {};
  filteredBills.forEach(bill => {
    (bill.items || []).forEach(item => {
      // bill_items only have categoryType, not categoryId
      const catType = item.categoryType || 'bar';
      const isKit = catType === 'kitchen';
      const catName = isKit ? splitReport.kitchenLabel : splitReport.barLabel;
      const catColor = isKit ? '#FDCB6E' : '#6C5CE7';
      if (!categorySales[catName]) categorySales[catName] = { qty: 0, revenue: 0, color: catColor, type: catType };
      categorySales[catName].qty += (item.quantity || 0);
      categorySales[catName].revenue += (item.price || 0) * (item.quantity || 0);
    });
  });
  const categoryData = Object.entries(categorySales).sort((a,b) => b[1].revenue - a[1].revenue);

  const handlePrintReport = () => {
    const html = buildPrintableReport();
    printHTML(html);
  };

  function buildPrintableReport() {
    return `<!DOCTYPE html>
<html><head><title>${reportType === 'daily' ? 'Daily' : reportType === 'monthly' ? 'Monthly' : 'Session'} Sales Report</title>
<style>
  @page { margin: 10mm; size: A4; }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: 'Courier New', monospace; padding: 10mm; font-size: 12px; color: #000; max-width: 800px; margin: 0 auto; }
  .c { text-align: center; } .b { font-weight: bold; }
  .d { border-top: 2px dashed #000; margin: 8px 0; }
  .r { display: flex; justify-content: space-between; padding: 2px 0; }
  h2 { font-size: 16px; text-align: center; margin-bottom: 6px; }
  h3 { font-size: 13px; margin: 10px 0 4px; text-transform: uppercase; border-bottom: 1px solid #ccc; padding-bottom: 2px; }
  table { width: 100%; border-collapse: collapse; margin: 4px 0 8px; }
  th { text-align: left; padding: 3px 6px; font-size: 10px; border-bottom: 1px solid #000; text-transform: uppercase; }
  td { padding: 2px 6px; font-size: 11px; border-bottom: 1px solid #eee; }
  .total-row td { font-weight: bold; border-top: 2px solid #000; border-bottom: none; }
  .section-title { font-size: 12px; font-weight: bold; margin: 12px 0 4px; padding: 3px 6px; background: #f0f0f0; }
</style></head><body>

<div class="c b" style="font-size:20px">${config.restaurantName || 'RestoGrow POS'}</div>
${config.address ? `<div class="c" style="font-size:10px">${config.address}</div>` : ''}
<h2>${reportType.toUpperCase()} SALES REPORT</h2>
<div class="c">${reportLabel}</div>
<div class="d"></div>

<div class="r b"><span>Total Bills</span><span>${totalBills}</span></div>
<div class="r b"><span>Total Items Sold</span><span>${totalItems}</span></div>
<div class="r b" style="font-size:14px"><span>TOTAL REVENUE</span><span>${config.currency}${totalRevenue}</span></div>
<div class="d"></div>

<h3>Payment Breakdown</h3>
<div class="r"><span>Cash</span><span>${config.currency}${paymentSales.Cash}</span></div>
<div class="r"><span>Card</span><span>${config.currency}${paymentSales.Card}</span></div>
<div class="r"><span>UPI</span><span>${config.currency}${paymentSales.UPI}</span></div>
<div class="d"></div>

<h3>Sales Summary</h3>
${splitReport.isBarEnabled ? `<div class="r"><span>${splitReport.barLabel}: ${splitReport.barQty} items</span><span>${config.currency}${splitReport.barTotal}</span></div>` : ''}
${splitReport.isKitchenEnabled ? `<div class="r"><span>${splitReport.kitchenLabel}: ${splitReport.kitchenQty} items</span><span>${config.currency}${splitReport.kitchenTotal}</span></div>` : ''}
<div class="d"></div>

${splitReport.isBarEnabled ? `
<div class="section-title">${splitReport.barLabel.toUpperCase()} ITEMS</div>
<table>
<tr><th>Item</th><th style="text-align:center">Qty</th><th style="text-align:right">Revenue</th></tr>
