import { supabase } from '../utils/supabase';

// Helper for UUID if crypto.randomUUID isn't available
const getUUID = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

let _restaurantId = null;

// ===== MULTI-TENANT CONFIG =====
export function setTenant(id) {
  _restaurantId = id;
}

export function getTenant() {
  return _restaurantId;
}

// ===== AUTH =====
export async function authenticateUser(email, password) {
  const { data, error } = await supabase
    .from('users')
    .select('*')
    .eq('email', email)
    .eq('password', password);

  if (error || !data || data.length === 0) throw new Error('Invalid email or password');

  const user = data[0];
  setTenant(user.restaurant_id);
  return user;
}

// ===== MULTI-TENANT DATA SYNC =====
export async function syncAll() {
  if (!_restaurantId) return null;

  const tableNames = ['tables', 'sections', 'categories', 'menu_items', 'users', 'orders', 'order_items', 'bills', 'bill_items', 'sessions', 'config', 'inventory_log'];
  const results = {};

  try {
    const fetchPromises = tableNames.map(table => 
      supabase.from(table).select('*').eq('restaurant_id', _restaurantId)
    );

    // Also fetch restaurant status
    const restPromise = supabase.from('restaurants').select('status, name').eq('id', _restaurantId).single();

    const [responses, restRes] = await Promise.all([Promise.all(fetchPromises), restPromise]);

    if (restRes.data) {
      results.restaurant = restRes.data;
    }

    responses.forEach((res, index) => {
      const tableName = tableNames[index];
      if (res.error) {
        console.error(`Error fetching ${tableName}:`, res.error);
        return;
      }

      if (!res.data) return;

      if (tableName === 'config') {
        const cfg = { restaurantName: 'RestoGrow', currency: 'Γé╣', taxRate: 0, serviceChargeRate: 0 };
        res.data.forEach(r => {
          try { cfg[r.id] = JSON.parse(r.value); } catch { cfg[r.id] = r.value; }
        });
        results.config = cfg;
      } else {
        results[tableName] = res.data;
      }
    });

    // Map snake_case database records to camelCase for UI
    (results.orders || []).forEach(o => {
      o.tableId = o.tableId || o.table_id;
      o.items = (results.order_items || []).filter(item => {
        item.orderId = item.orderId || item.order_id;
        item.menuItemId = item.menuItemId || item.menu_item_id;
        item.categoryType = item.categoryType || item.category_type;
        return item.orderId === o.id;
      });
    });

    (results.bills || []).forEach(b => {
      b.orderId = b.orderId || b.order_id;
      b.billNumber = b.billNumber || b.bill_number;
      b.paymentMode = b.paymentMode || b.payment_mode;
      b.sessionId = b.sessionId || b.session_id;
      b.createdAt = b.createdAt || b.created_at;

      b.items = (results.bill_items || []).filter(item => {
        item.billId = item.billId || item.bill_id;
        item.categoryType = item.categoryType || item.category_type;
        item.quantity = item.quantity || item.qty || 0;
        return item.billId === b.id;
      });
    });

    return results;
  } catch (err) {
    console.error('syncAll critical error:', err);
    return null;
  }
}

// ===== GENERIC HELPERS =====
async function dbInsert(table, data) {
  const payload = { ...data, restaurant_id: _restaurantId };
  const { data: result, error } = await supabase
    .from(table)
    .insert([payload])
    .select()
    .single();
  if (error) {
    console.error(`dbInsert ${table} FAILED:`, error.message, 'payload keys:', Object.keys(payload));
    throw error;
  }
  return result;
}

async function dbUpdate(table, id, data) {
  const { error } = await supabase
    .from(table)
    .update(data)
    .eq('id', id)
    .eq('restaurant_id', _restaurantId);
  if (error) throw error;
}

async function dbDelete(table, id) {
  const { error } = await supabase
    .from(table)
    .delete()
    .eq('id', id)
    .eq('restaurant_id', _restaurantId);
  if (error) throw error;
}

